package com.example.oauth.client;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.web.servlet.view.InternalResourceViewResolver;

@SpringBootApplication
public class OAuthClientApplication {

    public static void main(String[] args) {
        SpringApplication.run(OAuthClientApplication.class, args);
    }

    @Bean
    public InternalResourceViewResolver defaultViewResolver() {
        return new InternalResourceViewResolver();
    }
}

import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class AuthorizationController {

    private static final String AUTHORIZATION_SERVER_URL = "https://authorization-server.com/oauth/authorize";
    private static final String CLIENT_ID = "your-client-id";
    private static final String REDIRECT_URI = "http://localhost:8080/callback";

    @GetMapping("/login")
    public String login() {
        StringBuilder authorizationUrl = new StringBuilder(AUTHORIZATION_SERVER_URL);
        authorizationUrl.append("?response_type=code");
        authorizationUrl.append("&client_id=").append(CLIENT_ID);
        authorizationUrl.append("&redirect_uri=").append(REDIRECT_URI);
        authorizationUrl.append("&scope=read write");

        return "redirect:" + authorizationUrl.toString();
    }
}